import { useState, useRef } from 'react';
import Icon from '../../components/common/Icon';
import { icons } from '../../config/icons';
import { FormInput, FormSelect, FormTextarea, FormSearchableSelect, FormPassword } from '../../components/common/FormFields';
import { validationRules } from '../../utils/validation';

const FormValidations = () => {

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    const phoneRegex = /^(09|\+639)\d{9}$/;

    const fnRef = useRef(null);
    const snRef = useRef(null);

    const [errors, setErrors] = useState({});
    const [formData, setFormData] = useState({ fn: '', sn: '', gender: '', dob: '', phone: '', email: '', address: '', un: '', password: '', tech: '' });
    const handleReset = (e) => { setFormData({ fn: '', sn: '', gender: '', dob: '', phone: '', email: '', address: '', un: '', password: '', tech: '' }); setErrors({}); };
    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData((prev) => ({ ...prev, [name]: value }));
        if (value.trim() !== '') {
            if (name === 'email') { setErrors(prev => ({ ...prev, email: !emailRegex.test(value) })); }
            else if (name === 'phone') { setErrors(prev => ({ ...prev, phone: !phoneRegex.test(value) })); }
            else if (name === 'password') { validatePassword(value); setErrors(prev => ({ ...prev, password: false })); }
            else { setErrors(prev => ({ ...prev, [name]: false })); }
        }
    };

    const validatePassword = (password) => {
        const complexity = validationRules.passwordComplexity(password, 6);
        return Object.values(complexity).every(Boolean);
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        let hasError = false;
        const newErrors = {};

        if (!formData.fn.trim()) { newErrors.fn = true; hasError = true; }
        if (!formData.sn.trim()) { newErrors.sn = true; hasError = true; }
        if (!formData.gender) { newErrors.gender = true; hasError = true; }
        if (!formData.dob) { newErrors.dob = true; hasError = true; }
        if (!formData.phone || !phoneRegex.test(formData.phone)) { newErrors.phone = true; hasError = true; }
        if (!formData.email || !emailRegex.test(formData.email)) { newErrors.email = true; hasError = true; }
        if (!formData.address.trim()) { newErrors.address = true; hasError = true; }
        if (!formData.un.trim()) { newErrors.un = true; hasError = true; }

        const techMatch = techCustomOptions.some(opt => opt.value === formData.tech);
        if (!techMatch) { newErrors.tech = 'Please select a valid option from the list'; hasError = true; }

        if (!validatePassword(formData.password)) { newErrors.password = true; hasError = true; }

        setErrors(newErrors);
        if (hasError) {
            if (newErrors.fn) fnRef.current?.focus();
            else if (newErrors.sn) snRef.current?.focus();
            return;
        }

        console.log(formData);
    };


    const techOptions = [
        { label: 'React.js', value: 'react' },
        { label: 'Vue.js', value: 'vue' },
        { label: 'Angular', value: 'angular' },
        { label: 'Svelte', value: 'svelte' },
        { label: 'Next.js', value: 'next' },
        { label: 'Vite', value: 'vite' },
        { label: 'Tailwind CSS', value: 'tailwind' },
        { label: 'Node.js', value: 'node' },
        { label: 'PHP', value: 'php' },
        { label: 'Javascript', value: 'javascript' },
    ];

    const techCustomOptions = techOptions.map(opt => ({
        ...opt,
        desc: `Description for ${opt.label}`
    }));

    return (
        <div className='admin-pager'>
            <header className='admin-pager-head'>
                <div className='admin-pager-title'> <span><h2>Form Validations</h2><p>Input Validations Layouts</p></span>  </div>
            </header>
            <div className='admin-pager-body'>
                <div className='flex-column'>
                    <div className='w5'>
                        <div className='pagelet'>
                            <div className='pagelet-head'><h4>SAMPLE</h4></div>
                            <div className='pagelet-in flex-row'>
                                <div className='input-case'>
                                    <p>Input without validation</p>
                                    <input type='text' name='sample' placeholder='Type here...' />
                                    <small>Example help text that remains unchanged.</small>
                                </div>
                                <div className='input-case valid'>
                                    <p>Valid Input</p>
                                    <div className='input-group right'>
                                        <input type='email' name='mail-valid' placeholder='Type here...' />
                                        <Icon icon={icons.success} className='input-icon' />
                                    </div>
                                    <em>This is a valid Sample</em>
                                    <small>Example help text that remains unchanged.</small>
                                </div>
                                <div className='input-case invalid'>
                                    <p>Invalid Input</p>
                                    <div className='input-group right'>
                                        <input type='email' name='mail-invalid' placeholder='Type here...' />
                                        <Icon icon={icons.invalid} className='input-icon' />
                                    </div>
                                    <em>Oh no! This is an invalid Sample</em>
                                    <small>Example help text that remains unchanged.</small>
                                </div>
                                <div className='input-case'>
                                    <FormSearchableSelect name='tech' label='Searchable Input' options={techOptions} placeholder='Search tech...' onChange={(e) => console.log('Selected:', e.target.value)} hints='Try searching "React" or "Vite"' />
                                    <small>Example searchable select field.</small>
                                </div>
                            </div>
                            <div className='pagelet-foot'>
                                <button className='button btn-outlined' disabled >Reset</button>
                                <button className='button' disabled >Submit</button>
                            </div>
                        </div>
                    </div>
                    {/* --:-- */}
                    <form onSubmit={handleSubmit} className='w5' noValidate>
                        <div className='pagelet'>
                            <div className='pagelet-head'><h4>FORM SUBMIT</h4></div>
                            <div className='pagelet-in'>
                                <div className='form-case'>
                                    <div className='form-row-fx'>
                                        <div className='w5-fx'> <FormInput label='First Name' name='fn' placeholder='First Name' value={formData.fn} onChange={handleChange} error={errors.fn} inputRef={fnRef} required /> </div>
                                        <div className='w5-fx'> <FormInput label='Last Name' name='sn' placeholder='Last Name' value={formData.sn} onChange={handleChange} error={errors.sn} inputRef={snRef} required /> </div>
                                    </div>
                                    <div className='form-row'>
                                        <div className='w5'>
                                            <div className='form-row-fx'>
                                                <div className='w4-fx'> <FormSelect label='Gender' name='gender' value={formData.gender} onChange={handleChange} error={errors.gender} options={[{ label: 'Male', value: '1' }, { label: 'Female', value: '2' }]} required /> </div>
                                                <div className='w6-fx'> <FormInput label='Birthday' name='dob' type='date' value={formData.dob} onChange={handleChange} error={errors.dob} required /> </div>
                                            </div>
                                        </div>
                                        <div className='w5'> <FormInput label='Phone' name='phone' type='tel' placeholder='09XXXXXXXXX or +639XXXXXXXXX' value={formData.phone} onChange={handleChange} error={errors.phone} required /> </div>
                                    </div>
                                    <FormInput label='Email Address' name='email' type='email' placeholder='Email Address' value={formData.email} onChange={handleChange} error={errors.email} required />
                                    <FormTextarea label='Complete Address' name='address' placeholder='Complete Address' value={formData.address} onChange={handleChange} error={errors.address} required />
                                    <FormSearchableSelect required label='Searchable Input (Customized)' name='tech' value={formData.tech} error={errors.tech} options={techCustomOptions} placeholder='Search tech...' onChange={handleChange} hints='Try searching "React" or "Vite"' renderOption={(opt) => (<span className='wrap custom-option-test' style={{ padding: '10px' }}> <b>{opt.label}</b> <p>{opt.desc}</p> </span>)} />
                                    <div className='form-dvr'></div>
                                    <div className='form-row'>
                                        <div className='w5'> <FormInput label='Username' name='un' placeholder='Username' value={formData.un} onChange={handleChange} error={errors.un} iconLeft={icons.user} required /> </div>
                                        <div className='w5'> <FormPassword label='Password' name='password' value={formData.password} onChange={handleChange} error={errors.password} required minChars={6} /> </div>
                                    </div>
                                </div>
                            </div>
                            <div className='pagelet-foot'>
                                <button type='button' onClick={handleReset} className='button btn-outlined' >Reset</button>
                                <button type='submit' className='button' >Submit</button>
                            </div>
                        </div>
                    </form>
                </div>
            </div>
        </div>);
};
export default FormValidations;